import{_ as s,o,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"Outbound Session Mirroring Refactor (Issue","description":"Track outbound session mirroring refactor notes, decisions, tests, and open items.","frontmatter":{"title":"Outbound Session Mirroring Refactor (Issue","description":"Track outbound session mirroring refactor notes, decisions, tests, and open items."},"headers":[],"relativePath":"refactor/outbound-session-mirroring.md","filePath":"refactor/outbound-session-mirroring.md","lastUpdated":null}'),t={name:"refactor/outbound-session-mirroring.md"};function r(d,e,a,l,c,u){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="outbound-session-mirroring-refactor-issue-1520" tabindex="-1"><a class="header-anchor" href="#outbound-session-mirroring-refactor-issue-1520">#</a> Outbound Session Mirroring Refactor (Issue #1520)</h1><h2 id="status" tabindex="-1"><a class="header-anchor" href="#status">#</a> Status</h2><ul><li>In progress.</li><li>Core + plugin channel routing updated for outbound mirroring.</li><li>Gateway send now derives target session when sessionKey is omitted.</li></ul><h2 id="context" tabindex="-1"><a class="header-anchor" href="#context">#</a> Context</h2><p>Outbound sends were mirrored into the <em>current</em> agent session (tool session key) rather than the target channel session. Inbound routing uses channel/peer session keys, so outbound responses landed in the wrong session and first-contact targets often lacked session entries.</p><h2 id="goals" tabindex="-1"><a class="header-anchor" href="#goals">#</a> Goals</h2><ul><li>Mirror outbound messages into the target channel session key.</li><li>Create session entries on outbound when missing.</li><li>Keep thread/topic scoping aligned with inbound session keys.</li><li>Cover core channels plus bundled extensions.</li></ul><h2 id="implementation-summary" tabindex="-1"><a class="header-anchor" href="#implementation-summary">#</a> Implementation Summary</h2><ul><li>New outbound session routing helper: <ul><li><code>src/infra/outbound/outbound-session.ts</code></li><li><code>resolveOutboundSessionRoute</code> builds target sessionKey using <code>buildAgentSessionKey</code> (dmScope + identityLinks).</li><li><code>ensureOutboundSessionEntry</code> writes minimal <code>MsgContext</code> via <code>recordSessionMetaFromInbound</code>.</li></ul></li><li><code>runMessageAction</code> (send) derives target sessionKey and passes it to <code>executeSendAction</code> for mirroring.</li><li><code>message-tool</code> no longer mirrors directly; it only resolves agentId from the current session key.</li><li>Plugin send path mirrors via <code>appendAssistantMessageToSessionTranscript</code> using the derived sessionKey.</li><li>Gateway send derives a target session key when none is provided (default agent), and ensures a session entry.</li></ul><h2 id="thread-topic-handling" tabindex="-1"><a class="header-anchor" href="#thread-topic-handling">#</a> Thread/Topic Handling</h2><ul><li>Slack: replyTo/threadId -&gt; <code>resolveThreadSessionKeys</code> (suffix).</li><li>Discord: threadId/replyTo -&gt; <code>resolveThreadSessionKeys</code> with <code>useSuffix=false</code> to match inbound (thread channel id already scopes session).</li><li>Telegram: topic IDs map to <code>chatId:topic:&lt;id&gt;</code> via <code>buildTelegramGroupPeerId</code>.</li></ul><h2 id="extensions-covered" tabindex="-1"><a class="header-anchor" href="#extensions-covered">#</a> Extensions Covered</h2><ul><li>Matrix, MS Teams, Mattermost, BlueBubbles, Nextcloud Talk, Zalo, Zalo Personal, Nostr, Tlon.</li><li>Notes: <ul><li>Mattermost targets now strip <code>@</code> for DM session key routing.</li><li>Zalo Personal uses DM peer kind for 1:1 targets (group only when <code>group:</code> is present).</li><li>BlueBubbles group targets strip <code>chat_*</code> prefixes to match inbound session keys.</li><li>Slack auto-thread mirroring matches channel ids case-insensitively.</li><li>Gateway send lowercases provided session keys before mirroring.</li></ul></li></ul><h2 id="decisions" tabindex="-1"><a class="header-anchor" href="#decisions">#</a> Decisions</h2><ul><li><strong>Gateway send session derivation</strong>: if <code>sessionKey</code> is provided, use it. If omitted, derive a sessionKey from target + default agent and mirror there.</li><li><strong>Session entry creation</strong>: always use <code>recordSessionMetaFromInbound</code> with <code>Provider/From/To/ChatType/AccountId/Originating*</code> aligned to inbound formats.</li><li><strong>Target normalization</strong>: outbound routing uses resolved targets (post <code>resolveChannelTarget</code>) when available.</li><li><strong>Session key casing</strong>: canonicalize session keys to lowercase on write and during migrations.</li></ul><h2 id="tests-added-updated" tabindex="-1"><a class="header-anchor" href="#tests-added-updated">#</a> Tests Added/Updated</h2><ul><li><code>src/infra/outbound/outbound-session.test.ts</code><ul><li>Slack thread session key.</li><li>Telegram topic session key.</li><li>dmScope identityLinks with Discord.</li></ul></li><li><code>src/agents/tools/message-tool.test.ts</code><ul><li>Derives agentId from session key (no sessionKey passed through).</li></ul></li><li><code>src/gateway/server-methods/send.test.ts</code><ul><li>Derives session key when omitted and creates session entry.</li></ul></li></ul><h2 id="open-items-follow-ups" tabindex="-1"><a class="header-anchor" href="#open-items-follow-ups">#</a> Open Items / Follow-ups</h2><ul><li>Voice-call plugin uses custom <code>voice:&lt;phone&gt;</code> session keys. Outbound mapping is not standardized here; if message-tool should support voice-call sends, add explicit mapping.</li><li>Confirm if any external plugin uses non-standard <code>From/To</code> formats beyond the bundled set.</li></ul><h2 id="files-touched" tabindex="-1"><a class="header-anchor" href="#files-touched">#</a> Files Touched</h2><ul><li><code>src/infra/outbound/outbound-session.ts</code></li><li><code>src/infra/outbound/outbound-send-service.ts</code></li><li><code>src/infra/outbound/message-action-runner.ts</code></li><li><code>src/agents/tools/message-tool.ts</code></li><li><code>src/gateway/server-methods/send.ts</code></li><li>Tests in: <ul><li><code>src/infra/outbound/outbound-session.test.ts</code></li><li><code>src/agents/tools/message-tool.test.ts</code></li><li><code>src/gateway/server-methods/send.test.ts</code></li></ul></li></ul>',21)])])}const m=s(t,[["render",r]]);export{g as __pageData,m as default};
